  ('judicial-f0899a01-moex-00086', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列何者非屬行政事實行為？', '["軍隊進行戰鬥之行為", "拆除違章建築之行為", "徵收土地之行為", "監測空氣品質之行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00087', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '食品加工廠未依消防法裝設煙霧警報器，造成火災，受僱員工受困火場，發生嚴重勞災事件，該加工廠後 遭主管機關停業30日之處置，該處置屬於下列何種行政處分？', '["警告性處分", "紀律懲戒性處分", "裁罰性不利處分", "管制性行政處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00088', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '行政罰法第 8條規定：「不得因不知法規而免除行政處罰責任。但按其情節，得減輕或免除其處罰。」下 列敘述何者錯誤？', '["「按其情節」，係指行為人不知法規之可責性高低而言", "如行為人並非「不知法規」，縱屬初犯或欠缺經驗，仍無但書有關減輕或免除處罰規定之適用", "行為人須對自己的行為究係違反何法規之規定有所認知，始得加以處罰", "「不知法規」，係指行為人不知法規所「禁止」或「要求應為」之行為或不行為義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00089', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依行政罰法規定，行政機關對現行違反行政法上義務之行為人得為之處置，不包括下列何者？', '["拘提", "確認其身分", "即時制止其行為", "為保全證據之措施"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00090', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '對於同一違法行為，若依法可處以罰鍰、刑罰、予以懲戒或懲處，得在民事上請求損害賠償，則於下列何 種情形後，不得再處以罰鍰？', '["刑罰", "懲戒", "懲處", "民事賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00091', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '工廠負責人甲因重大過失致工廠違法排放廢氣，經裁處罰鍰未依限繳納，行政執行機關執行時應如何處理？', '["應向甲提起一般給付訴訟", "甲顯有逃匿之虞時，得命其提供相當擔保，限期履行，並得限制其住居", "得向法院聲請核發對甲之禁止命令", "得對該工廠核發禁止命令"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00092', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政執行之敘述，下列何者錯誤？', '["行政執行須有法律依據，且須符合法定之強制執行要件及程序", "行政機關實施行政執行，僅能採用法律所規定之方法", "作成行政行為之行政機關即為行政執行之行政機關", "行政機關採取行政執行手段前，原則上須先以書面命義務人限期履行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00093', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於公法上金錢給付義務執行之敘述，下列何者正確？', '["原處分機關應自行執行，不得請求其他機關協助", "義務人如有逃匿之虞，執行機關即得聲請法院裁定管收", "得對義務人核發限制其進入一般消費場所之禁止命令", "拘提係由行政執行機關派執行員持拘票執行之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00094', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於依行政程序法規定進行之聽證，下列敘述何者正確？', '["行政機關認為有必要或法規明文規定時，舉行聽證", "無法定程序要遵守", "蒐集意見之範圍限於聽證事件之當事人", "經聽證程序而作成之行政處分，人民對之如有不服者，須經訴願後提起行政訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00095', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於政府資訊公開及閱覽卷宗之敘述，下列何者正確？', '["資訊公開請求權之主體得為任何人民，而閱覽卷宗請求權限於行政程序之當事人或利害關係人", "請求資訊公開者必須以主張或維護其法律上利益有必要者為限", "請求閱覽卷宗遭拒者，原則上應直接提起行政救濟", "行政機關應主動公開當事人之卷宗資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "9ce997984cf8", "answer_pdf_sha1": "68e95dc310c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
